#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(param);
use File::Spec;

my $log_dir = '/path/to/log/directory'; # Set your log directory here

my $filename = param('logfile');
if (!$filename) {
    print "Content-Type: text/plain\n\n";
    print "No logfile specified.\n";
    exit;
}

# Canonicalize and validate file path
my $resolved_path = File::Spec->rel2abs($log_dir . '/' . $filename);
if (!File::Spec->file_name_is_absolute($resolved_path) || !grep { $resolved_path =~ /^$_/ } map { File::Spec->canonpath($_) } ($log_dir)) {
    print "Content-Type: text/plain\n\n";
    print "Invalid or unsafe logfile path.\n";
    exit;
}

# Open and read the log file
open(my $fh, '<', $resolved_path) or do {
    print "Content-Type: text/plain\n\n";
    print "Could not open logfile: $!\n";
    exit;
};

print "Content-Type: text/plain\n\n";

while (my $line = <$fh>) {
    print "$line";
}

close($fh);